namespace sv_2191b2623670448e9d7280c4fb586b05.Services;

public class WarehouseState
{
    private string _currentWarehouseId = "warehouse-a";

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName => Warehouses
        .FirstOrDefault(w => w.Id == _currentWarehouseId)?.Name ?? "Unknown";

    public event Action? OnChange;

    public static IReadOnlyList<WarehouseInfo> Warehouses { get; } =
    [
        new("warehouse-a", "Warehouse A — East"),
        new("warehouse-b", "Warehouse B — West"),
        new("warehouse-c", "Warehouse C — Central"),
    ];

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

public record WarehouseInfo(string Id, string Name);

namespace sv_2191b2623670448e9d7280c4fb586b05.Services;

public class InventoryAlertService
{
    private readonly Random _random = new();

    private int _lastLowStockCount;
    public int LastLowStockCount => _lastLowStockCount;

    public event Action? OnAlertCountChanged;

    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulates a database query — returns a random number between 0 and 15.
        return Task.FromResult(_random.Next(0, 16));
    }

    public async Task RefreshAsync(string warehouseId)
    {
        var count = await GetLowStockCountAsync(warehouseId);
        _lastLowStockCount = count;
        OnAlertCountChanged?.Invoke();
    }
}

