@using sv_2191b2623670448e9d7280c4fb586b05.Services
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable
@rendermode InteractiveServer

<PageTitle>Dashboard — @WarehouseState.CurrentWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>
<p class="lead">Currently viewing: <strong>@WarehouseState.CurrentWarehouseName</strong></p>

<div class="card mt-3" style="max-width: 400px;">
    <div class="card-body">
        <h5 class="card-title">Low-Stock Alerts</h5>
        <p class="display-4 text-danger">@AlertService.LastLowStockCount</p>
        <p class="text-muted">Items below minimum level. Refreshes every 10 seconds.</p>
    </div>
</div>

@code {
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private Action? _warehouseHandler;

    protected override void OnInitialized()
    {
        _warehouseHandler = () => InvokeAsync(OnWarehouseChanged);
        WarehouseState.OnChange += _warehouseHandler;

        AlertService.OnAlertCountChanged += OnAlertChanged;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await AlertService.RefreshAsync(WarehouseState.CurrentWarehouseId);
            StartPolling();
        }
    }

    private async void OnWarehouseChanged()
    {
        // Warehouse changed — refresh immediately and restart polling.
        StopPolling();
        await AlertService.RefreshAsync(WarehouseState.CurrentWarehouseId);
        StartPolling();
        await InvokeAsync(StateHasChanged);
    }

    private void OnAlertChanged() => InvokeAsync(StateHasChanged);

    private void StartPolling()
    {
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        _ = PollLoopAsync(_cts.Token);
    }

    private async Task PollLoopAsync(CancellationToken cancellationToken)
    {
        try
        {
            while (await _timer!.WaitForNextTickAsync(cancellationToken))
            {
                await AlertService.RefreshAsync(WarehouseState.CurrentWarehouseId);
            }
        }
        catch (OperationCanceledException) { }
    }

    private void StopPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _timer?.Dispose();
        _cts = null;
        _timer = null;
    }

    public void Dispose()
    {
        StopPolling();

        if (_warehouseHandler is not null)
            WarehouseState.OnChange -= _warehouseHandler;

        AlertService.OnAlertCountChanged -= OnAlertChanged;
    }
}

